import { invokeFunction as invoke } from "../utils/zcutils";

export function executeAxisOperators(data, mapping, operators, customOperators) {
    let _this = this,
        _axes = new Array(0);
    operators.map(d => {
        let _thisTrack = mapping[d];
        if (_thisTrack) {
            let condition = _thisTrack.condition ? _thisTrack.condition.call(_this) : true,
                customOperator = customOperators && customOperators[d],
                mark,
                holder = _thisTrack.holder ? _thisTrack.holder.call(_this) : null;
            if (customOperator && customOperator.parser) {
                mark = invoke(true, customOperator.parser, this, data, 'render', condition);
            } else {
                mark = _thisTrack.operator.call(this, data, 'render', condition);
            }

            if (customOperator && customOperator.extender) {
                mark = invoke(true, customOperator.extender, this, mark, this.axis);
            }
            _axes.push({
                mark,
                holder
            });
        } else {
            throw 'Axis operator is not defined';
        }
    });
    return _axes;
}
